record.field:
import base64
import json
import urllib.request
import urllib.error

get_param  = env['ir.config_parameter'].sudo().get_param
agent_url  = get_param('labelcast.agent.url',   'http://localhost:7777')
api_token  = get_param('labelcast.api.token',   '')
report_xml = 'product.report_producttemplatelabel'
copies     = int(get_param('labelcast.copies',  '1'))

if hasattr(records, '__iter__'):
    record_ids = records.ids
else:
    record_ids = [record.id]

if not record_ids:
    raise UserError("No products selected.")

errors = []

for rec_id in record_ids:
    try:
        pdf_bytes, _ = env['ir.actions.report']._render_qweb_pdf(
            report_xml, [rec_id]
        )
        rec        = env['product.template'].browse(rec_id)
        label_name = rec.name or str(rec_id)
        pdf_b64    = base64.b64encode(pdf_bytes).decode('utf-8')

        payload = json.dumps({
            'pdf':    pdf_b64,
            'copies': copies,
            'label':  label_name,
        }).encode('utf-8')

        req = urllib.request.Request(
            url     = agent_url.rstrip('/') + '/print',
            data    = payload,
            method  = 'POST',
            headers = {
                'Content-Type':  'application/json',
                'X-Print-Token': api_token,
                'Accept':        'application/json',
            },
        )

        try:
            with urllib.request.urlopen(req, timeout=15) as resp:
                result = json.loads(resp.read().decode('utf-8'))
        except urllib.error.HTTPError as e:
            errors.append(f"{label_name}: HTTP {e.code}")
        except urllib.error.URLError as e:
            errors.append(f"{label_name}: Cannot reach agent at {agent_url} ({e.reason})")

    except Exception as e:
        errors.append(f"Product {rec_id}: {str(e)}")

if errors:
    raise UserError("LabelCast errors:\n\n" + "\n".join(errors))

import base64
import json
import urllib.request
import urllib.error

get_param  = env['ir.config_parameter'].sudo().get_param
agent_url  = get_param('labelcast.agent.url',   'http://localhost:7777')
api_token  = get_param('labelcast.api.token',   '')
report_xml = 'stock.report_lot_label'
copies     = int(get_param('labelcast.copies',  '1'))

if hasattr(records, '__iter__'):
    record_ids = records.ids
else:
    record_ids = [record.id]

if not record_ids:
    raise UserError("No lots selected.")

errors = []

for rec_id in record_ids:
    try:
        pdf_bytes, _ = env['ir.actions.report']._render_qweb_pdf(
            report_xml, [rec_id]
        )
        rec        = env['stock.lot'].browse(rec_id)
        label_name = rec.name or str(rec_id)
        pdf_b64    = base64.b64encode(pdf_bytes).decode('utf-8')

        payload = json.dumps({
            'pdf':    pdf_b64,
            'copies': copies,
            'label':  label_name,
        }).encode('utf-8')

        req = urllib.request.Request(
            url     = agent_url.rstrip('/') + '/print',
            data    = payload,
            method  = 'POST',
            headers = {
                'Content-Type':  'application/json',
                'X-Print-Token': api_token,
                'Accept':        'application/json',
            },
        )

        try:
            with urllib.request.urlopen(req, timeout=15) as resp:
                result = json.loads(resp.read().decode('utf-8'))
        except urllib.error.HTTPError as e:
            errors.append(f"{label_name}: HTTP {e.code}")
        except urllib.error.URLError as e:
            errors.append(f"{label_name}: Cannot reach agent ({e.reason})")

    except Exception as e:
        errors.append(f"Lot {rec_id}: {str(e)}")

if errors:
    raise UserError("LabelCast errors:\n\n" + "\n".join(errors))
